from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST', 'GET'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Retrieve data from the request body (POST) or a query parameter (GET)
    yaml_input = request.data if request.data else request.args.get('data', '')

    if not yaml_input:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # yaml.load() is unsafe and can lead to Remote Code Execution (RCE)
        parsed_data = yaml.safe_load(yaml_input)

        # Ensure the parsed data is a type that can be serialized to JSON
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
    except TypeError as e:
        return jsonify({"error": f"Parsed YAML is not JSON serializable: {str(e)}"}), 500
